  createQuizAndDisplay(): void {
    this.createQuiz(false, true);
  }

  scrollToSettingsSection(section: "general" | "timing" | "grade"): void {
    const elementId = section === "general"
      ? "quiz-general-section"
      : section === "timing"
        ? "quiz-timing-section"
        : "quiz-grade-section";
    const target = document.getElementById(elementId);
    target?.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  toggleQuestion(questionId: number, checked: boolean): void {
    if (checked) {
      if (!this.selectedQuestionIds.includes(questionId)) {
        this.selectedQuestionIds.push(questionId);
      }
      return;
    }
    this.selectedQuestionIds = this.selectedQuestionIds.filter((id) => id !== questionId);
  }

  removeSelectedQuestion(questionId: number): void {
    this.selectedQuestionIds = this.selectedQuestionIds.filter((id) => id !== questionId);
  }

  moveSelectedQuestion(questionId: number, direction: -1 | 1): void {
    const index = this.selectedQuestionIds.indexOf(questionId);
    if (index < 0) {
      return;
    }
    const target = index + direction;
    if (target < 0 || target >= this.selectedQuestionIds.length) {
      return;
    }
    const swapped = [...this.selectedQuestionIds];
    const temp = swapped[index];
    swapped[index] = swapped[target];
    swapped[target] = temp;
    this.selectedQuestionIds = swapped;
  }

  repaginateSelectedQuestions(): void {
    const selectedSet = new Set(this.selectedQuestionIds);
    const ordered = this.questionBank
      .filter((item) => selectedSet.has(Number(item.questionBankId)))
      .map((item) => Number(item.questionBankId));
    if (ordered.length > 0) {
      this.selectedQuestionIds = ordered;
    }
    this.statusMessage = "Question order updated.";
    this.errorMessage = "";
  }

  toggleBulkSelectionMode(): void {
    this.bulkSelectionMode = !this.bulkSelectionMode;
    this.statusMessage = this.bulkSelectionMode
      ? "Multiple selection mode enabled."
      : "Multiple selection mode disabled.";
    this.errorMessage = "";
  }

  saveMaximumGrade(): void {
    this.statusMessage = `Maximum grade set to ${Number(this.quizForm.gradeOut || 0).toFixed(2)}.`;
    this.errorMessage = "";
  }

  clearSelectedQuestions(): void {
    this.selectedQuestionIds = [];
  }

  isSelected(questionId: number): boolean {
    return this.selectedQuestionIds.includes(questionId);
  }

  selectedQuestions(): any[] {
    return this.selectedQuestionIds
      .map((id) => this.questionBank.find((item) => item.questionBankId === id))
      .filter(Boolean);
  }

  totalSelectedPoints(): number {
    return this.selectedQuestions().reduce((sum, item) => sum + Number(item.points ?? 0), 0);
  }

  filteredQuestionBank(): any[] {
    let rows = [...this.questionBank];

    if (!this.questionBankView.includeOldQuestions) {
      rows = rows.filter((item) => String(item.status ?? "Ready").toLowerCase() !== "archived");
    }

    const category = this.questionBankView.category;
    if (category && category !== "ALL") {
      if (category.startsWith("COURSE:")) {
        const courseId = Number(category.replace("COURSE:", ""));
        rows = rows.filter((item) => Number(item.courseId) === courseId);
      } else if (category.startsWith("MODULE:")) {
        const moduleTag = category.replace("MODULE:", "").trim().toLowerCase();
        rows = rows.filter((item) => String(item.moduleTag ?? "").trim().toLowerCase() === moduleTag);
      }
    }

    const tag = this.questionBankView.tagFilter.trim().toLowerCase();
    if (tag) {
      rows = rows.filter((item) => {
        const topic = String(item.topicTag ?? "").trim().toLowerCase();
        const module = String(item.moduleTag ?? "").trim().toLowerCase();
        if (this.questionBankView.includeSubcategories) {
          return topic.includes(tag) || module.includes(tag);
        }
        return topic === tag || module === tag;
      });
    }

    const query = this.librarySearch.trim().toLowerCase();
    if (!query) {
      return rows;
    }

    return rows.filter((item) =>
      String(item.prompt ?? "").toLowerCase().includes(query) ||
      String(item.questionType ?? "").toLowerCase().includes(query) ||
      String(item.topicTag ?? "").toLowerCase().includes(query) ||
      String(item.moduleTag ?? "").toLowerCase().includes(query) ||
      String(item.questionCode ?? "").toLowerCase().includes(query) ||
      String(item.createdBy ?? "").toLowerCase().includes(query)
    );
  }

  categoryOptions(): Array<{ value: string; label: string }> {
    const options = new Map<string, string>();
    options.set("ALL", "All categories");

    const selectedCourse = this.currentCourse();
    if (selectedCourse) {
      options.set(`COURSE:${selectedCourse.courseId}`, `${selectedCourse.title} (Course)`);
    }

    for (const item of this.questionBank) {
      const moduleTag = String(item.moduleTag ?? "").trim();
      if (moduleTag) {
        options.set(`MODULE:${moduleTag}`, moduleTag);
      }
    }

    return Array.from(options.entries()).map(([value, label]) => ({ value, label }));
  }

  isAllVisibleSelected(): boolean {
    const visibleIds = this.filteredQuestionBank().map((item) => Number(item.questionBankId));
    if (visibleIds.length === 0) {
      return false;
    }
    return visibleIds.every((id) => this.selectedQuestionIds.includes(id));
  }

  toggleVisibleSelection(checked: boolean): void {
    const visibleIds = this.filteredQuestionBank().map((item) => Number(item.questionBankId));
    if (checked) {
      const merged = new Set([...this.selectedQuestionIds, ...visibleIds]);
      this.selectedQuestionIds = Array.from(merged);
      return;
    }
    const hidden = new Set(visibleIds);
    this.selectedQuestionIds = this.selectedQuestionIds.filter((id) => !hidden.has(id));
  }

  openCreateQuestionQuick(): void {
    this.openCreateModal("MCQ");
  }

  showQuestionPrompt(): boolean {
    return this.questionBankView.showQuestionTextMode !== "HIDDEN";
  }

  showQuestionMeta(): boolean {
    return this.questionBankView.showQuestionTextMode === "TEXT_WITH_META";
  }

  selectedCountLabel(): string {
    const count = this.selectedQuestionIds.length;
    return `${count} item${count === 1 ? "" : "s"} selected`;
  }

  questionTypeLabel(type: QuestionType | string): string {
    return this.questionTypes.find((item) => item.value === type)?.label ?? type;
  }

  setQuestionType(type: QuestionType): void {
    this.questionForm.questionType = type;

    if ((type === "MCQ" || type === "MULTI_SELECT") && this.questionForm.options.length < 2) {
      this.questionForm.options = [
        { text: "", correct: type === "MCQ" },
        { text: "", correct: false }
      ];
    }

    if (type === "TRUE_FALSE" && !["True", "False"].includes(this.questionForm.trueFalseCorrect)) {
      this.questionForm.trueFalseCorrect = "True";
    }

    if (type === "MATCHING") {
      if (this.questionForm.matchingPrompts.length < 2) {
        this.questionForm.matchingPrompts = ["", "", "", ""];
      }
      if (this.questionForm.matchingOptions.length < 2) {
        this.questionForm.matchingOptions = ["", "", "", ""];
      }
      if (this.questionForm.matchingCorrect.length < this.questionForm.matchingPrompts.length) {
        this.questionForm.matchingCorrect = this.questionForm.matchingPrompts.map((_, idx) => this.questionForm.matchingCorrect[idx] ?? "");
      }
    }

    this.statusMessage = `${this.questionTypeLabel(type)} selected.`;
    this.errorMessage = "";
  }

  applyPromptTool(tool: EditorTool): void {
    this.applyEditorTool(tool, "questionPromptEditor", { field: "PROMPT" });
  }

  applyOptionTool(index: number, tool: EditorTool): void {
    this.applyEditorTool(tool, `choiceEditor-${index}`, { field: "OPTION", index });
  }

  openAddElementPanel(): void {
    if (!this.questionForm.mediaType) {
      this.questionForm.mediaType = "IMAGE";
    }
    this.statusMessage = "Add Element enabled. Set media type and URL below.";
    this.errorMessage = "";
    const mediaInput = document.getElementById("questionMediaUrl") as HTMLInputElement | null;
    setTimeout(() => mediaInput?.focus(), 0);
  }

  previewOptions(): string[] {
    if (this.questionForm.questionType === "TRUE_FALSE") {
      return ["True", "False"];
    }
    if (this.questionForm.questionType === "MCQ" || this.questionForm.questionType === "MULTI_SELECT") {
      return this.questionForm.options
        .map((option) => option.text.trim())
        .filter(Boolean);
    }
    return [];
  }

  matchingOptionChoices(): string[] {
    return this.questionForm.matchingOptions
      .map((item) => item.trim())
      .filter(Boolean)
      .filter((item, index, array) => array.indexOf(item) === index);
  }

  togglePublish(quizId: number, published: boolean): void {
    this.clearMessages();
    this.lecturerService.publishQuiz(quizId, published).subscribe({
      next: () => {
        this.statusMessage = "Quiz publication updated.";
        this.loadQuizzes();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to update quiz status"
    });
  }

  private clearMessages(): void {
    this.statusMessage = "";
    this.errorMessage = "";
  }

  private defaultOpenDate(): string {
    const value = new Date();
    const year = value.getFullYear();
    const month = String(value.getMonth() + 1).padStart(2, "0");
    const day = String(value.getDate()).padStart(2, "0");
    return `${year}-${month}-${day}`;
  }

  private defaultDueDate(): string {
    const value = new Date();
    value.setDate(value.getDate() + 7);
    const year = value.getFullYear();
    const month = String(value.getMonth() + 1).padStart(2, "0");
    const day = String(value.getDate()).padStart(2, "0");
    return `${year}-${month}-${day}`;
  }

  private combineDateTime(dateValue: string, timeValue: string): string | null {
    if (!dateValue || !timeValue) {
      return null;
    }
    return `${dateValue}T${timeValue}:00`;
  }

  private currentCourse(): any | null {
    return this.courses.find((course) => course.courseId === this.selectedCourseId) ?? null;
  }

  private persistQuizDraftToStorage(): void {
    const payload = {
      courseId: this.selectedCourseId,
      questionIds: this.selectedQuestionIds
    };
    sessionStorage.setItem("edusim.quizDraft", JSON.stringify(payload));
  }

  private restoreQuizDraftFromStorage(): void {
    if (this.isBankMode()) {
      return;
    }

    const raw = sessionStorage.getItem("edusim.quizDraft");
    if (!raw) {
      return;
    }

    try {
      const parsed = JSON.parse(raw);
      const storedCourseId = Number(parsed?.courseId ?? 0);
      const ids: number[] = Array.isArray(parsed?.questionIds)
        ? parsed.questionIds.map((item: unknown) => Number(item)).filter((item: number) => Number.isFinite(item) && item > 0)
        : [];

      if (storedCourseId > 0 && (!this.selectedCourseId || this.selectedCourseId === storedCourseId)) {
        this.selectedCourseId = storedCourseId;
      }
      if (ids.length > 0) {
        this.selectedQuestionIds = Array.from(new Set(ids));
      }
    } catch {
      // ignore invalid draft payload
    } finally {
      sessionStorage.removeItem("edusim.quizDraft");
    }
  }

  private applyRequestedModeMessage(): void {
    if (!this.requestedMode) {
      return;
    }

    if (this.requestedMode === "create") {
      this.statusMessage = "Course selected. You can add new quiz now.";
    } else if (this.requestedMode === "edit") {
      this.statusMessage = "Course selected. Use Quiz List & Publish to edit existing quiz.";
    } else if (this.requestedMode === "bank") {
      this.statusMessage = "Course selected. Manage question bank items for this course.";
    }

    this.requestedMode = "";
  }

  private defaultQuestionForm() {
    return {
      questionType: "MCQ" as QuestionType,
      difficultyLevel: "MEDIUM" as DifficultyLevel,
      topicTag: "",
      moduleTag: "",
      prompt: "",
      explanation: "",
      mediaUrl: "",
      mediaType: "" as MediaType,
      points: 1,
      randomizeAnswers: false,
      options: [
        { text: "", correct: true },
        { text: "", correct: false }
      ],
      trueFalseCorrect: "True",
      shortAnswer: "",
      shortAnswerKeywords: "",
      matchingPrompts: ["", "", "", ""],
      matchingOptions: ["", "", "", ""],
      matchingCorrect: ["", "", "", ""],
      allowDuplicateResponse: false,
      scoringType: "EXACT" as MatchingScoringType
    };
  }

  private buildQuestionPayload(): any {
    if (!this.questionForm.prompt.trim()) {
      throw new Error("Question text is required.");
    }
    if (!this.questionForm.topicTag.trim()) {
      throw new Error("Topic tag is required.");
    }

    const basePayload = {
      courseId: this.selectedCourseId,
      questionType: this.questionForm.questionType,
      difficultyLevel: this.questionForm.difficultyLevel,
      topicTag: this.questionForm.topicTag.trim(),
      moduleTag: this.questionForm.moduleTag.trim() || this.currentCourse()?.title || "General",
      prompt: this.questionForm.prompt.trim(),
      explanation: this.questionForm.explanation.trim(),
      mediaUrl: this.questionForm.mediaUrl.trim(),
      mediaType: this.questionForm.mediaType || null,
      points: Math.max(1, Number(this.questionForm.points))
    };

    if (this.questionForm.questionType === "SHORT_ANSWER") {
      const answer = this.questionForm.shortAnswer.trim();
      if (!answer) {
        throw new Error("Expected answer is required.");
      }
      const keywords = this.questionForm.shortAnswerKeywords
        .split(",")
        .map((item) => item.trim().toLowerCase())
        .filter(Boolean);
      return {
        ...basePayload,
        options: { keywords },
        correctAnswer: answer.toLowerCase()
      };
    }

    if (this.questionForm.questionType === "MATCHING") {
      const left = this.questionForm.matchingPrompts
        .map((item) => item.trim())
        .filter(Boolean);
      const right = this.matchingOptionChoices();

      if (left.length < 2) {
        throw new Error("Please add at least 2 prompts for matching.");
      }
      if (right.length < 2) {
        throw new Error("Please add at least 2 possible answers for matching.");
      }

      const usedAnswers = new Set<string>();
      const correctMap: Record<string, string> = {};
      for (let i = 0; i < this.questionForm.matchingPrompts.length; i++) {
        const prompt = this.questionForm.matchingPrompts[i]?.trim();
        if (!prompt) {
          continue;
        }
        const selected = this.questionForm.matchingCorrect[i]?.trim();
        const chosen = selected || right[i] || "";
        if (!chosen || !right.includes(chosen)) {
          throw new Error("Please set valid correct matching for each prompt.");
        }
        if (!this.questionForm.allowDuplicateResponse && usedAnswers.has(chosen)) {
          throw new Error("Duplicate response not allowed. Choose unique correct answer for each prompt.");
        }
        usedAnswers.add(chosen);
        correctMap[prompt] = chosen;
      }

      return {
        ...basePayload,
        options: {
          left,
          right,
          allowDuplicateResponse: this.questionForm.allowDuplicateResponse,
          scoringType: this.questionForm.scoringType
        },
        correctAnswer: correctMap
      };
    }

    if (this.questionForm.questionType === "TRUE_FALSE") {
      return {
        ...basePayload,
        options: ["True", "False"],
        correctAnswer: this.questionForm.trueFalseCorrect
      };
    }

    const options = this.questionForm.options
      .map((option) => ({ text: option.text.trim(), correct: option.correct }))
      .filter((option) => option.text);

    if (options.length < 2) {
      throw new Error("Please add at least 2 answers.");
    }

    if (this.questionForm.questionType === "MULTI_SELECT") {
      const correctAnswers = options
        .filter((option) => option.correct)
        .map((option) => option.text);

      if (correctAnswers.length === 0) {
        throw new Error("Select at least one correct answer.");
      }

      return {
        ...basePayload,
        options: options.map((option) => option.text),
        correctAnswer: correctAnswers
      };
    }

    const correctAnswer = options.find((option) => option.correct)?.text;
    if (!correctAnswer) {
      throw new Error("Please select one correct answer.");
    }

    return {
      ...basePayload,
      options: options.map((option) => option.text),
      correctAnswer
    };
  }

  private applyEditorTool(
    tool: EditorTool,
    textareaId: string,
    target: { field: "PROMPT" } | { field: "OPTION"; index: number }
  ): void {
    const textarea = document.getElementById(textareaId) as HTMLTextAreaElement | null;
    if (!textarea) {
      return;
    }

    const currentValue = this.readEditorValue(target);
    const start = Math.max(0, Math.min(textarea.selectionStart ?? 0, currentValue.length));
    const end = Math.max(start, Math.min(textarea.selectionEnd ?? start, currentValue.length));
    const selectedText = currentValue.slice(start, end);

    const replacement = this.editorReplacement(tool, selectedText);
    const updatedValue = `${currentValue.slice(0, start)}${replacement}${currentValue.slice(end)}`;
    const cursor = start + replacement.length;

    this.writeEditorValue(target, updatedValue);

    setTimeout(() => {
      const updatedTextarea = document.getElementById(textareaId) as HTMLTextAreaElement | null;
      if (!updatedTextarea) {
        return;
      }
      updatedTextarea.focus();
      updatedTextarea.setSelectionRange(cursor, cursor);
    }, 0);
  }

  private readEditorValue(target: { field: "PROMPT" } | { field: "OPTION"; index: number }): string {
    if (target.field === "PROMPT") {
      return String(this.questionForm.prompt ?? "");
    }
    return String(this.questionForm.options[target.index]?.text ?? "");
  }

  private writeEditorValue(target: { field: "PROMPT" } | { field: "OPTION"; index: number }, value: string): void {
    if (target.field === "PROMPT") {
      this.questionForm.prompt = value;
      return;
    }

    if (!this.questionForm.options[target.index]) {
      return;
    }
    this.questionForm.options[target.index].text = value;
  }

  private editorReplacement(tool: EditorTool, selectedText: string): string {
    const trimmed = selectedText.trim();

    if (tool === "BOLD") {
      const content = trimmed || "bold text";
      return `**${content}**`;
    }

    if (tool === "ITALIC") {
      const content = trimmed || "italic text";
      return `*${content}*`;
    }

    if (tool === "HEADING") {
      if (!selectedText.trim()) {
        return "## Heading";
      }
      return this.prefixEachLine(selectedText, "## ");
    }

    if (tool === "QUOTE") {
      if (!selectedText.trim()) {
        return "> Quote";
      }
      return this.prefixEachLine(selectedText, "> ");
    }

    if (tool === "LINK") {
      const label = trimmed || "link text";
      return `[${label}](https://example.com)`;
    }

    if (tool === "IMAGE") {
      const altText = trimmed || "image description";
      return `![${altText}](https://example.com/image.jpg)`;
    }

    if (tool === "BULLET_LIST") {
      if (!selectedText.trim()) {
        return "- Item 1\n- Item 2";
      }
      return this.prefixEachLine(selectedText, "- ");
    }

    if (tool === "NUMBER_LIST") {
      if (!selectedText.trim()) {
        return "1. Item 1\n2. Item 2";
      }
      const lines = selectedText
        .split(/\r?\n/)
        .map((line) => line.trim())
        .filter((line) => line.length > 0);
      return lines.map((line, index) => `${index + 1}. ${line}`).join("\n");
    }

    return selectedText;
  }

  private prefixEachLine(text: string, prefix: string): string {
    const lines = text
      .split(/\r?\n/)
      .map((line) => line.trim())
      .filter((line) => line.length > 0);

    if (lines.length === 0) {
      return `${prefix}Item`;
    }

    return lines.map((line) => `${prefix}${line}`).join("\n");
  }
}
<div class="container quiz-page" (click)="showTypeMenu = false">
  <section class="style-hero panel">
    <div class="style-hero-top">
      <div class="style-brand-wrap">
        <img src="assets/edusim-logo.svg" alt="EduSIM">
      </div>
      <div class="style-search-wrap">
        <input type="text" placeholder="Search for question, quiz, or module..." [ngModel]="librarySearch" (ngModelChange)="librarySearch = $event" name="heroSearch">
      </div>
      <div class="style-meta">
        <span>English</span>
        <span class="dot"></span>
        <span>Lecturer</span>
      </div>
    </div>
    <div class="style-hero-main">
      <div class="style-hero-copy">
        <h2>Question Studio</h2>
        <p>Build quizzes and question banks with a structured workflow in one place.</p>
        <div class="style-crumb">Home &gt; Quiz Builder</div>
      </div>
      <div class="style-hero-image"></div>
    </div>
  </section>

  <header class="studio-top">
    <a class="back-link" routerLink="/lecturer/manage">
      <span>&#8249;</span>
      Back to Content
    </a>
    <h1>
      @if (isBankMode()) {
        <span>Question Bank</span>
      } @else if (isQuestionsMode()) {
        <span>Quiz Questions</span>
      } @else if (isSettingsMode()) {
        <span>Quiz Settings</span>
      } @else {
        <span>Quiz Overview</span>
      }
    </h1>
    <div class="course-pick">
      <label for="courseId">Course</label>
      <select id="courseId" [ngModel]="selectedCourseId ?? ''" (ngModelChange)="onCourseChange($event)" name="courseId">
        <option value="">Select course</option>
        @for (course of courses; track course.courseId) {
          <option [value]="course.courseId">{{ course.title }}</option>
        }
      </select>
    </div>
  </header>

  <nav class="studio-tabs moodle-main-tabs" aria-label="Quiz workspace tabs">
    <a [routerLink]="['/lecturer/quiz-overview']" [queryParams]="tabQueryParams()" [class.active]="isQuizMode()">Quiz</a>
    <a [routerLink]="['/lecturer/quiz-settings']" [queryParams]="tabQueryParams()" [class.active]="isSettingsMode()">Settings</a>
    <a [routerLink]="['/lecturer/quiz-builder']" [queryParams]="tabQueryParams()" [class.active]="isQuestionsMode()">Questions</a>
    <a [routerLink]="['/lecturer/question-bank']" [queryParams]="tabQueryParams()" [class.active]="isBankMode()">Question bank</a>
  </nav>

  @if (statusMessage) {
    <p class="ok">{{ statusMessage }}</p>
  }
  @if (errorMessage) {
    <p class="error">{{ errorMessage }}</p>
  }

  @if (isBankMode()) {
    <section class="published-block">
      <header>
        <h2>Question Bank Filters</h2>
        <span>{{ questionBank.length }} question(s)</span>
      </header>
      <div class="filter-grid">
        <div class="field-block">
          <label>Topic / Module</label>
          <input [(ngModel)]="questionFilters.topicTag" name="topicFilter" placeholder="Data Integration">
        </div>
        <div class="field-block">
          <label>Difficulty</label>
          <select [(ngModel)]="questionFilters.difficultyLevel" name="difficultyFilter">
            <option value="">All</option>
            @for (level of difficultyLevels; track level.value) {
              <option [value]="level.value">{{ level.label }}</option>
            }
          </select>
        </div>
        <div class="field-block">
          <label>Type</label>
          <select [(ngModel)]="questionFilters.questionType" name="typeFilter">
            <option value="">All</option>
            @for (type of questionTypes; track type.value) {
              <option [value]="type.value">{{ type.label }}</option>
            }
          </select>
        </div>
        <div class="field-block">
          <label>Search</label>
          <input [(ngModel)]="questionFilters.search" name="searchFilter" placeholder="keyword">
        </div>
        <div class="field-block">
          <label>Created From</label>
          <input type="date" [(ngModel)]="questionFilters.createdFrom" name="createdFrom">
        </div>
        <div class="field-block">
          <label>Created To</label>
          <input type="date" [(ngModel)]="questionFilters.createdTo" name="createdTo">
        </div>
      </div>
      <div class="filter-actions">
        <button class="btn btn-action" type="button" (click)="applyQuestionFilters()">Apply Filter</button>
        <button class="btn btn-outline" type="button" (click)="resetQuestionFilters()">Reset</button>
      </div>
    </section>
  }

  @if (isQuestionsMode()) {
    <section class="published-block mode-note">
      <header>
        <h2>Questions (Quiz Page)</h2>
      </header>
      <p class="muted">
        This page is for arranging questions inside the current quiz. For full question library management, open
        <strong>Question Bank</strong> tab.
      </p>
      <div class="filter-actions">
        <a class="btn btn-outline" [routerLink]="['/lecturer/question-bank']" [queryParams]="tabQueryParams()">
          Open Question Bank
        </a>
      </div>
    </section>

    <section class="studio-layout">
      <section class="main-editor">
        <div class="editor-card">
          <div class="field-block">
            <label for="quizTitle">Name *</label>
            <input id="quizTitle" name="quizTitle" [(ngModel)]="quizForm.title" placeholder="Unit Quiz">
          </div>

          <div class="field-block">
            <label for="description">Instructions / Description</label>
            <textarea
              id="description"
              name="description"
              rows="3"
              [(ngModel)]="quizForm.description"
              placeholder="This quiz covers key topics from the lesson.">
            </textarea>
          </div>

          <div class="split-row">
            <div class="field-block compact">
              <label for="gradeOutQuestions">Grade Out Of</label>
              <div class="inline-group">
                <input id="gradeOutQuestions" name="gradeOutQuestions" type="number" min="1" [(ngModel)]="quizForm.gradeOut">
                <span>points</span>
              </div>
            </div>

            <div class="field-block compact">
              <label>Due Date / Time</label>
              <div class="inline-group due">
                <input type="date" [(ngModel)]="quizForm.closeDate" name="closeDateQuestions">
                <input type="time" [(ngModel)]="quizForm.closeTime" name="closeTimeQuestions">
              </div>
            </div>
          </div>
        </div>

        <section class="questions-editor">
          <header class="questions-head moodle-questions-head">
            <div>
              <h2>Questions</h2>
              <p class="moodle-subline">Questions: {{ selectedQuestionIds.length }} | {{ quizForm.published ? "This quiz is open" : "Draft mode" }}</p>
            </div>
            <div class="grade-box">
              <label>Maximum grade</label>
              <div class="grade-inline">
                <input type="number" min="1" [(ngModel)]="quizForm.gradeOut" name="maximumGradeQuestion">
                <button class="btn btn-outline" type="button" (click)="saveMaximumGrade()">Save</button>
              </div>
              <p>Total of marks: {{ totalSelectedPoints() | number : "1.2-2" }}</p>
            </div>
          </header>

          <div class="question-actions moodle-actions">
            <div class="moodle-right-actions">
              <button class="btn btn-outline" type="button" (click)="repaginateSelectedQuestions()">Repaginate</button>
              <button class="btn btn-outline" type="button" (click)="toggleBulkSelectionMode()">
                {{ bulkSelectionMode ? "Disable multi select" : "Select multiple items" }}
              </button>
            </div>
            <div class="moodle-right-actions">
              <label class="check-row">
                <input type="checkbox" [(ngModel)]="quizForm.shuffleQuestions" name="shuffleQuestionOrder">
                Shuffle
              </label>
              <button class="btn btn-action" type="button" (click)="openQuestionLibrary()">Add Existing</button>
              <div class="create-wrap" (click)="$event.stopPropagation()">
                <button class="btn btn-secondary" type="button" (click)="openTypeMenu($event)">
                  Create New
                  <span class="arrow">&#9662;</span>
                </button>

                @if (showTypeMenu) {
                  <div class="type-menu">
                    @for (type of questionTypes; track type.value) {
                      <button type="button" (click)="openCreateModal(type.value)">{{ type.menuLabel }}</button>
                    }
                  </div>
                }
              </div>
            </div>
          </div>

          @if (selectedQuestions().length === 0) {
            <div class="empty-state">
              <p class="title">Ready to begin adding quiz content?</p>
              <p>Click Add Existing or Create New to get started.</p>
            </div>
          } @else {
            <ul class="moodle-question-list">
              @for (item of selectedQuestions(); track item.questionBankId; let i = $index) {
                <li>
                  <div class="drag-col">
                    <button class="mini-icon" type="button" [disabled]="i === 0" (click)="moveSelectedQuestion(item.questionBankId, -1)">&#8593;</button>
                    <button class="mini-icon" type="button" [disabled]="i === selectedQuestions().length - 1" (click)="moveSelectedQuestion(item.questionBankId, 1)">&#8595;</button>
                  </div>
                  <div class="idx-col">{{ i + 1 }}</div>
                  <div class="question-col">
                    <p class="selected-title">{{ item.prompt }}</p>
                    <p class="selected-meta">{{ questionTypeLabel(item.questionType) }} | {{ item.topicTag || "-" }}</p>
                  </div>
                  <div class="bank-col">
                    <span class="bank-pill">{{ item.moduleTag || "Question bank" }}</span>
                  </div>
                  <div class="version-col">
                    <select>
                      <option>Always latest</option>
                    </select>
                  </div>
                  <div class="table-actions compact">
                    <button class="mini-icon" type="button" (click)="openEditQuestion(item)">&#9998;</button>
                    <button class="mini-icon" type="button" (click)="removeSelectedQuestion(item.questionBankId)">&#128465;</button>
                  </div>
                  <div class="points-col">
                    {{ (item.points ?? 1) | number : "1.2-2" }}
                  </div>
                </li>
              }
            </ul>
            <div class="add-bottom">
              <button class="btn btn-outline" type="button" (click)="openQuestionLibrary()">Add</button>
            </div>
          }
        </section>

        <footer class="editor-footer">
          <button class="btn btn-action" type="button" [disabled]="savingQuiz" (click)="createQuiz(true)">
            {{ savingQuiz ? "Saving..." : "Save and Close" }}
          </button>
          <button class="btn btn-outline" type="button" [disabled]="savingQuiz" (click)="createQuiz(false)">
            Save
          </button>
          <button class="btn btn-outline" type="button" [disabled]="savingQuiz" (click)="cancelDraft()">
            Cancel
          </button>
          <label class="visibility-toggle">
            <input type="checkbox" name="publishedQuestions" [(ngModel)]="quizForm.published">
            Visibility
          </label>
        </footer>
      </section>

      <aside class="setup-side">
        <article class="setup-card">
          <h3>Timing & Display</h3>
          <div class="input-inline">
            <label>Time limit (minutes)</label>
            <input type="number" min="1" [(ngModel)]="quizForm.timeLimitMinutes" name="timeLimitQuestions">
          </div>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.shuffleQuestions" name="shuffleQuestionsQuestions">
            Shuffle question order
          </label>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.shuffleAnswers" name="shuffleAnswersQuestions">
            Shuffle answer options
          </label>
          <div class="input-inline">
            <label>Question display mode</label>
            <select [(ngModel)]="quizForm.questionDisplayMode" name="questionDisplayModeQuestions">
              <option value="ONE_BY_ONE">One by one</option>
              <option value="ALL_AT_ONCE">All at once</option>
            </select>
          </div>
        </article>

        <article class="setup-card">
          <h3>Attempts & Completion</h3>
          <div class="input-inline">
            <label>Attempts allowed</label>
            <input type="number" min="1" [(ngModel)]="quizForm.maxAttempts" name="maxAttemptsQuestions">
          </div>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.unlockAfterVideos" name="unlockAfterVideosQuestions">
            Lock until mandatory videos complete
          </label>
        </article>

        <article class="setup-card">
          <h3>Evaluation & Feedback</h3>
          <div class="input-inline">
            <label>Pass mark (%)</label>
            <input type="number" min="0" max="100" [(ngModel)]="quizForm.passingMark" name="passingMarkQuestions">
          </div>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.showResultImmediately" name="showResultImmediatelyQuestions">
            Release result immediately
          </label>
          @if (!quizForm.showResultImmediately) {
            <div class="input-inline">
              <label>Result release date</label>
              <input type="date" [(ngModel)]="quizForm.resultReleaseDate" name="resultReleaseDateQuestions">
            </div>
            <div class="input-inline">
              <label>Result release time</label>
              <input type="time" [(ngModel)]="quizForm.resultReleaseTime" name="resultReleaseTimeQuestions">
            </div>
          }
          <p class="side-detail">Total selected points: {{ totalSelectedPoints() }}</p>
        </article>
      </aside>
    </section>
  }

  @if (isSettingsMode()) {
    <section class="studio-layout">
      <section class="main-editor">
        <div class="editor-card" id="quiz-general-section">
          <div class="field-block">
            <label for="quizTitleSettings">Quiz Name *</label>
            <input id="quizTitleSettings" name="quizTitleSettings" [(ngModel)]="quizForm.title" placeholder="Unit Quiz">
          </div>

          <div class="split-row">
            <div class="field-block compact">
              <label for="gradeOutSettings">Grade Out Of</label>
              <div class="inline-group">
                <input id="gradeOutSettings" name="gradeOutSettings" type="number" min="1" [(ngModel)]="quizForm.gradeOut">
                <span>points</span>
              </div>
            </div>
            <div class="field-block compact">
              <label>Open Date / Time</label>
              <div class="inline-group due">
                <input type="date" [(ngModel)]="quizForm.openDate" name="openDateSettings">
                <input type="time" [(ngModel)]="quizForm.openTime" name="openTimeSettings">
              </div>
            </div>
          </div>

          <div class="field-block compact">
            <label>Close Date / Time</label>
            <div class="inline-group due">
              <input type="date" [(ngModel)]="quizForm.closeDate" name="closeDateSettings">
              <input type="time" [(ngModel)]="quizForm.closeTime" name="closeTimeSettings">
            </div>
          </div>

          <div class="field-block">
            <label for="quizDescriptionSettings">Description / Instructions</label>
            <textarea
              id="quizDescriptionSettings"
              name="quizDescriptionSettings"
              rows="4"
              [(ngModel)]="quizForm.description"
              placeholder="This quiz covers key topics from the lesson.">
            </textarea>
          </div>
        </div>

        <section class="new-quiz-flow-card">
          <h3>New Quiz</h3>
          <button class="new-quiz-flow-link" type="button" (click)="scrollToSettingsSection('general')">
            <span class="new-quiz-flow-icon">&#9662;</span>
            General
          </button>
          <button class="new-quiz-flow-link" type="button" (click)="scrollToSettingsSection('timing')">
            <span class="new-quiz-flow-icon">&#9662;</span>
            Timing
          </button>
          <button class="new-quiz-flow-link" type="button" (click)="scrollToSettingsSection('grade')">
            <span class="new-quiz-flow-icon">&#9662;</span>
            Grade
          </button>
        </section>

        <footer class="editor-footer settings-flow-actions">
          <button class="btn btn-action" type="button" [disabled]="savingQuiz" (click)="createQuiz(true)">
            {{ savingQuiz ? "Saving..." : "Save and return to course" }}
          </button>
          <button class="btn btn-outline" type="button" [disabled]="savingQuiz" (click)="createQuizAndDisplay()">
            Save and display
          </button>
          <button class="btn btn-outline" type="button" [disabled]="savingQuiz" (click)="cancelDraft()">Cancel</button>
        </footer>
      </section>

      <aside class="setup-side">
        <article class="setup-card" id="quiz-timing-section">
          <h3>Timing & Display</h3>
          <div class="input-inline">
            <label>Time limit (minutes)</label>
            <input type="number" min="1" [(ngModel)]="quizForm.timeLimitMinutes" name="timeLimitSettings">
          </div>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.shuffleQuestions" name="shuffleQuestionsSettings">
            Shuffle question order
          </label>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.shuffleAnswers" name="shuffleAnswersSettings">
            Shuffle answer options
          </label>
          <div class="input-inline">
            <label>Question display mode</label>
            <select [(ngModel)]="quizForm.questionDisplayMode" name="questionDisplayModeSettings">
              <option value="ONE_BY_ONE">One by one</option>
              <option value="ALL_AT_ONCE">All at once</option>
            </select>
          </div>
        </article>

        <article class="setup-card">
          <h3>Attempts & Completion</h3>
          <div class="input-inline">
            <label>Attempts allowed</label>
            <input type="number" min="1" [(ngModel)]="quizForm.maxAttempts" name="maxAttemptsSettings">
          </div>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.unlockAfterVideos" name="unlockAfterVideosSettings">
            Lock until mandatory videos complete
          </label>
        </article>

        <article class="setup-card" id="quiz-grade-section">
          <h3>Evaluation & Feedback</h3>
          <div class="input-inline">
            <label>Pass mark (%)</label>
            <input type="number" min="0" max="100" [(ngModel)]="quizForm.passingMark" name="passingMarkSettings">
          </div>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.showResultImmediately" name="showResultImmediatelySettings">
            Release result immediately
          </label>
          @if (!quizForm.showResultImmediately) {
            <div class="input-inline">
              <label>Result release date</label>
              <input type="date" [(ngModel)]="quizForm.resultReleaseDate" name="resultReleaseDateSettings">
            </div>
            <div class="input-inline">
              <label>Result release time</label>
              <input type="time" [(ngModel)]="quizForm.resultReleaseTime" name="resultReleaseTimeSettings">
            </div>
          }
          <p class="side-detail">Selected question count: {{ selectedQuestionIds.length }}</p>
        </article>

        <article class="setup-card">
          <h3>Auto-Select Questions</h3>
          <div class="input-inline">
            <label>Question count (when nothing selected)</label>
            <input type="number" min="1" [(ngModel)]="quizForm.autoSelectCount" name="autoSelectCountSettings">
          </div>
          <p class="side-detail">Uses current filter criteria to auto-pick latest questions.</p>
        </article>
      </aside>
    </section>
  }

  @if (isResultsMode() || isQuizMode()) {
    <section class="published-block">
      <header>
        <h2>Quiz List & Publish</h2>
        <span>{{ quizzes.length }} quiz(s)</span>
      </header>

      @if (quizzes.length === 0) {
        <p class="muted">No quiz in selected course.</p>
      } @else {
        <table>
          <thead>
            <tr>
              <th>Quiz</th>
              <th>Due date</th>
              <th>Time</th>
                <th>Attempts</th>
                <th>Pass</th>
                <th>Result release</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
            @for (quiz of quizzes; track quiz.quizId) {
              <tr>
                <td>{{ quiz.title }}</td>
                <td>{{ quiz.closeAt ? (quiz.closeAt | date : "mediumDate") : "-" }}</td>
                <td>{{ quiz.timeLimitMinutes }} min</td>
                <td>{{ quiz.maxAttempts }}</td>
                <td>{{ quiz.passingMark }}%</td>
                <td>
                  @if (quiz.showResultImmediately) {
                    Immediate
                  } @else {
                    {{ quiz.resultReleaseAt ? (quiz.resultReleaseAt | date : "medium") : "-" }}
                  }
                </td>
                <td>
                  <span class="badge" [class.warn]="!quiz.published">
                    {{ quiz.published ? "Published" : "Draft" }}
                  </span>
                </td>
                <td class="table-actions">
                  <button class="btn btn-outline" type="button" (click)="togglePublish(quiz.quizId, !quiz.published)">
                    {{ quiz.published ? "Unpublish" : "Publish" }}
                  </button>
                  <button class="btn btn-outline icon-only-btn" type="button" title="Preview" aria-label="Preview" (click)="openQuizPreview(quiz.quizId)">
                    <svg class="icon-svg" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                      <path d="M1 12s4-7 11-7 11 7 11 7-4 7-11 7S1 12 1 12Z"></path>
                      <circle cx="12" cy="12" r="3"></circle>
                    </svg>
                  </button>
                  <button class="btn btn-outline" type="button" (click)="duplicateQuiz(quiz.quizId)">
                    Duplicate
                  </button>
                  <a
                    class="btn btn-outline"
                    routerLink="/lecturer/monitoring"
                    [queryParams]="{ courseId: selectedCourseId ?? quiz.courseId, courseTitle: currentCourseTitle() || quiz.courseTitle, quizId: quiz.quizId }">
                    Monitoring
                  </a>
                  <button class="btn btn-danger btn-outline icon-only-btn" type="button" title="Delete quiz" aria-label="Delete quiz" (click)="deleteQuiz(quiz.quizId, quiz.title)">
                    <svg class="icon-svg" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                      <path d="M3 6h18"></path>
                      <path d="M8 6V4h8v2"></path>
                      <path d="M6 6l1 14h10l1-14"></path>
                      <path d="M10 10v7M14 10v7"></path>
                    </svg>
                  </button>
                </td>
              </tr>
            }
          </tbody>
        </table>
      }
    </section>
  }

  @if (isBankMode()) {
    <section class="main-editor">
      <div class="library-tools question-bank-tools">
        <div class="tool-field">
          <label>Select a category</label>
          <select [(ngModel)]="questionBankView.category" name="questionBankCategory">
            @for (category of categoryOptions(); track category.value) {
              <option [value]="category.value">{{ category.label }}</option>
            }
          </select>
        </div>
        <div class="tool-field">
          <label>Filter by tags</label>
          <input [(ngModel)]="questionBankView.tagFilter" name="questionBankTag" placeholder="e.g. ETL">
        </div>
        <div class="tool-field">
          <label>Show question text in list</label>
          <select [(ngModel)]="questionBankView.showQuestionTextMode" name="questionTextMode">
            @for (mode of questionTextModes; track mode.value) {
              <option [value]="mode.value">{{ mode.label }}</option>
            }
          </select>
        </div>
      </div>

      <div class="search-options-block">
        <p>Search options</p>
        <label class="check-row">
          <input type="checkbox" [(ngModel)]="questionBankView.includeSubcategories" name="includeSubcategories">
          Also show questions from subcategories
        </label>
        <label class="check-row">
          <input type="checkbox" [(ngModel)]="questionBankView.includeOldQuestions" name="includeOldQuestions">
          Also show old questions
        </label>
      </div>

      <div class="library-tools bank-search-line">
        <input type="text" name="librarySearch" placeholder="Search by question name or keyword..." [(ngModel)]="librarySearch">
        <span class="count">{{ selectedCountLabel() }}</span>
        <button type="button" class="btn btn-outline" (click)="openCreateQuestionQuick()">Create new question...</button>
        <button type="button" class="btn btn-action" [disabled]="selectedQuestionIds.length === 0" (click)="useSelectedInQuizDraft()">
          Use selected in quiz
        </button>
      </div>

      <div class="bank-table-wrap">
        <table class="bank-table">
          <thead>
            <tr>
              <th>
                <input
                  type="checkbox"
                  [checked]="isAllVisibleSelected()"
                  (change)="toggleVisibleSelection($any($event.target).checked)">
              </th>
              <th>Question</th>
              <th>Actions</th>
              <th>Status</th>
              <th>Version</th>
              <th>Created by</th>
              <th>Comments</th>
              <th>Usage</th>
              <th>Last used</th>
              <th>Modified by</th>
            </tr>
          </thead>
          <tbody>
            @for (item of filteredQuestionBank(); track item.questionBankId) {
              <tr>
                <td>
                  <input
                    type="checkbox"
                    [checked]="isSelected(item.questionBankId)"
                    (change)="toggleQuestion(item.questionBankId, $any($event.target).checked)">
                </td>
                <td>
                  <div class="question-cell">
                    <p class="question-code">{{ item.questionCode || ('Q_' + item.questionBankId) }}</p>
                    @if (showQuestionPrompt()) {
                      <p class="question-text">{{ item.prompt }}</p>
                    }
                    @if (showQuestionMeta()) {
                      <p class="question-sub">
                        {{ questionTypeLabel(item.questionType) }} | {{ item.topicTag || "-" }} | {{ item.points || 1 }} point(s)
                      </p>
                    }
                  </div>
                </td>
                <td>
                  <div class="table-actions compact">
                    <button class="btn btn-outline" type="button" (click)="openEditQuestion(item)">Edit</button>
                    <button class="btn btn-outline" type="button" (click)="deleteQuestion(item.questionBankId)">Delete</button>
                    <button class="btn btn-outline" type="button" (click)="toggleQuestion(item.questionBankId, !isSelected(item.questionBankId))">
                      {{ isSelected(item.questionBankId) ? "Remove" : "Add" }}
                    </button>
                  </div>
                </td>
                <td><span class="badge">{{ item.status || "Ready" }}</span></td>
                <td>v{{ item.version ?? 1 }}</td>
                <td>
                  <div class="meta-cell">
                    <span>{{ item.createdBy || "Lecturer" }}</span>
                    <small>{{ item.createdAt ? (item.createdAt | date : "medium") : "-" }}</small>
                  </div>
                </td>
                <td>{{ item.commentCount ?? 0 }}</td>
                <td>{{ item.usageCount ?? 0 }}</td>
                <td>{{ item.lastUsedAt ? (item.lastUsedAt | date : "mediumDate") : "Never" }}</td>
                <td>
                  <div class="meta-cell">
                    <span>{{ item.modifiedBy || (item.createdBy || "Lecturer") }}</span>
                    <small>{{ item.updatedAt ? (item.updatedAt | date : "medium") : "-" }}</small>
                  </div>
                </td>
              </tr>
            }
          </tbody>
        </table>

        @if (filteredQuestionBank().length === 0) {
          <div class="empty-state">
            <p class="title">No question found</p>
            <p>Try changing filters or create a new question.</p>
          </div>
        }
      </div>
    </section>
  }

  @if (showCreateModal) {
    <div class="modal-backdrop" (click)="closeCreateModal()">
      <section class="modal-shell question-modal" (click)="$event.stopPropagation()">
        <header class="modal-head">
          <h2>{{ editingQuestionId ? "Edit" : "New" }} {{ questionTypeLabel(questionForm.questionType) }} Question</h2>
          <button type="button" class="close-btn" (click)="closeCreateModal()">&#10005;</button>
        </header>

        <div class="modal-body">
          <form class="modal-form modern-question-form" (ngSubmit)="saveQuestion()">
            <section class="question-meta-grid">
              <div class="field-block type-selector-block">
                <label>Question Type</label>
                <div class="question-type-strip">
                  @for (type of questionTypeCardsUi; track type.value) {
                    <button
                      type="button"
                      class="question-type-card"
                      [class.active]="questionForm.questionType === type.value"
                      [attr.aria-pressed]="questionForm.questionType === type.value ? 'true' : 'false'"
                      (click)="setQuestionType(type.value)">
                      <span class="question-type-icon">{{ type.icon }}</span>
                      <span class="question-type-label">{{ type.shortLabel }}</span>
                    </button>
                  }
                </div>
              </div>

              <div class="field-block">
                <label>Topics Covered</label>
                <input [(ngModel)]="questionForm.topicTag" name="topicTag" placeholder="e.g. Algebra - Geometry" required>
              </div>

              <div class="field-block">
                <label>Grade</label>
                <select [(ngModel)]="questionForm.difficultyLevel" name="difficultyLevel">
                  @for (level of difficultyLevels; track level.value) {
                    <option [value]="level.value">{{ level.label }}</option>
                  }
                </select>
              </div>

              <div class="field-block">
                <label>Textbook / Module</label>
                <input [(ngModel)]="questionForm.moduleTag" name="moduleTag" placeholder="Module reference">
              </div>
            </section>

            <section class="question-editor-block">
              <h4>Question</h4>
              <div class="editor-row">
                <select class="editor-font" name="questionEditorFont">
                  <option>Aeonik</option>
                  <option>Inter</option>
                  <option>Manrope</option>
                </select>
                <div class="editor-tools">
                  <button type="button" class="tool-btn" title="Bold" (click)="applyPromptTool('BOLD')">B</button>
                  <button type="button" class="tool-btn" title="Italic" (click)="applyPromptTool('ITALIC')"><em>I</em></button>
                  <button type="button" class="tool-btn" title="Heading" (click)="applyPromptTool('HEADING')">H</button>
                  <button type="button" class="tool-btn" title="Quote" (click)="applyPromptTool('QUOTE')">&#8221;</button>
                  <button type="button" class="tool-btn tool-icon" title="Insert Link" (click)="applyPromptTool('LINK')">&#128279;</button>
                  <button type="button" class="tool-btn tool-icon" title="Insert Image" (click)="applyPromptTool('IMAGE')">&#128247;</button>
                  <button type="button" class="tool-btn" title="Bulleted List" (click)="applyPromptTool('BULLET_LIST')">&#8801;</button>
                  <button type="button" class="tool-btn" title="Numbered List" (click)="applyPromptTool('NUMBER_LIST')">&#9776;</button>
                </div>
                <button type="button" class="btn btn-action btn-mini" (click)="openAddElementPanel()">Add Element</button>
              </div>
              <textarea
                id="questionPromptEditor"
                rows="6"
                [(ngModel)]="questionForm.prompt"
                name="prompt"
                placeholder="Type your question..."
                required>
              </textarea>
            </section>

            @if (questionForm.questionType === "MCQ" || questionForm.questionType === "MULTI_SELECT") {
              <section class="choice-section">
                <div class="choice-grid">
                  @for (option of questionForm.options; track $index; let i = $index) {
                    <article class="choice-card">
                      <label class="choice-label">
                        @if (questionForm.questionType === "MCQ") {
                          <input
                            type="radio"
                            name="mcqCorrect"
                            [checked]="questionForm.options[i].correct"
                            (change)="setSingleCorrect(i)">
                        } @else {
                          <input
                            type="checkbox"
                            [checked]="questionForm.options[i].correct"
                            (change)="setMultiCorrect(i, $any($event.target).checked)">
                        }
                        <span>Choice {{ i + 1 }}</span>
                      </label>
                      <div class="editor-row compact">
                        <select class="editor-font" [name]="'choiceEditorFont' + i">
                          <option>Aeonik</option>
                          <option>Inter</option>
                          <option>Manrope</option>
                        </select>
                        <div class="editor-tools">
                          <button type="button" class="tool-btn" title="Bold" (click)="applyOptionTool(i, 'BOLD')">B</button>
                          <button type="button" class="tool-btn" title="Italic" (click)="applyOptionTool(i, 'ITALIC')"><em>I</em></button>
                          <button type="button" class="tool-btn" title="Heading" (click)="applyOptionTool(i, 'HEADING')">H</button>
                          <button type="button" class="tool-btn" title="Quote" (click)="applyOptionTool(i, 'QUOTE')">&#8221;</button>
                          <button type="button" class="tool-btn tool-icon" title="Insert Link" (click)="applyOptionTool(i, 'LINK')">&#128279;</button>
                          <button type="button" class="tool-btn tool-icon" title="Insert Image" (click)="applyOptionTool(i, 'IMAGE')">&#128247;</button>
                          <button type="button" class="tool-btn" title="Bulleted List" (click)="applyOptionTool(i, 'BULLET_LIST')">&#8801;</button>
                          <button type="button" class="tool-btn" title="Numbered List" (click)="applyOptionTool(i, 'NUMBER_LIST')">&#9776;</button>
                        </div>
                      </div>
                      <textarea
                        [id]="'choiceEditor-' + i"
                        [name]="'option' + i"
                        [(ngModel)]="questionForm.options[i].text"
                        placeholder="Type answer choice..."
                        rows="3"
                        required>
                      </textarea>
                      <div class="choice-actions">
                        <button type="button" class="mini-link" (click)="removeOption(i)">Remove choice</button>
                      </div>
                    </article>
                  }
                </div>
                <button type="button" class="btn btn-outline" (click)="addOption()">Add Choice</button>
              </section>
            }

            <section class="question-extra-grid">
              <div class="field-block">
                <label>Explanation (optional)</label>
                <textarea rows="3" [(ngModel)]="questionForm.explanation" name="explanation"></textarea>
              </div>
              <div class="matching-columns">
                <div class="field-block">
                  <label>Media Type</label>
                  <select [(ngModel)]="questionForm.mediaType" name="mediaType">
                    @for (type of mediaTypes; track type.value) {
                      <option [value]="type.value">{{ type.label }}</option>
                    }
                  </select>
                </div>
                <div class="field-block">
                  <label>Media URL</label>
                  <input id="questionMediaUrl" [(ngModel)]="questionForm.mediaUrl" name="mediaUrl" placeholder="https://...">
                </div>
              </div>
            </section>

            @if (questionForm.questionType === "TRUE_FALSE") {
              <div class="field-block">
                <label>Correct Answer</label>
                <div class="inline-pick">
                  <label class="inline-check"><input type="radio" name="tfCorrect" value="True" [(ngModel)]="questionForm.trueFalseCorrect">True</label>
                  <label class="inline-check"><input type="radio" name="tfCorrect" value="False" [(ngModel)]="questionForm.trueFalseCorrect">False</label>
                </div>
              </div>
            }

            @if (questionForm.questionType === "SHORT_ANSWER") {
              <div class="field-block">
                <label>Expected Answer</label>
                <input [(ngModel)]="questionForm.shortAnswer" name="shortAnswer" required>
              </div>
              <div class="field-block">
                <label>Keywords (comma separated)</label>
                <input [(ngModel)]="questionForm.shortAnswerKeywords" name="shortAnswerKeywords" placeholder="etl, transform, load">
              </div>
            }

            @if (questionForm.questionType === "MATCHING") {
              <section class="matching-setup">
                <h4>Question Setup</h4>
                <div class="matching-columns">
                  <div class="field-block">
                    <label>Prompts</label>
                    @for (prompt of questionForm.matchingPrompts; track $index; let i = $index) {
                      <div class="matching-row">
                        <input [name]="'prompt' + i" [placeholder]="'Prompt ' + (i + 1)" [(ngModel)]="questionForm.matchingPrompts[i]">
                        <button type="button" class="remove-answer" (click)="removeMatchingPrompt(i)">&#10005;</button>
                      </div>
                    }
                    <button type="button" class="mini-link" (click)="addMatchingPrompt()">+ Prompt</button>
                  </div>
                  <div class="field-block">
                    <label>Possible Answers</label>
                    @for (item of questionForm.matchingOptions; track $index; let i = $index) {
                      <div class="matching-row">
                        <input [name]="'possible' + i" [placeholder]="'Possible answer ' + (i + 1)" [(ngModel)]="questionForm.matchingOptions[i]">
                        <button type="button" class="remove-answer" (click)="removeMatchingOption(i)">&#10005;</button>
                      </div>
                    }
                    <button type="button" class="mini-link" (click)="addMatchingOption()">+ Option</button>
                  </div>
                </div>
                <div class="matching-correct">
                  <h4>Correct Answer Setup</h4>
                  @for (prompt of questionForm.matchingPrompts; track $index; let i = $index) {
                    @if (prompt.trim()) {
                      <div class="match-map-row">
                        <span>{{ prompt }}</span>
                        <select [name]="'correct' + i" [(ngModel)]="questionForm.matchingCorrect[i]">
                          <option value="">Select answer</option>
                          @for (choice of matchingOptionChoices(); track choice) {
                            <option [value]="choice">{{ choice }}</option>
                          }
                        </select>
                      </div>
                    }
                  }
                </div>
                <div class="matching-extra">
                  <label class="check-row">
                    <input type="checkbox" [(ngModel)]="questionForm.allowDuplicateResponse" name="allowDuplicateResponse">
                    Duplicate responses
                  </label>
                  <div class="inline-pick">
                    <label class="inline-check">
                      <input type="radio" name="matchingScoring" value="EXACT" [(ngModel)]="questionForm.scoringType">
                      Exact Match
                    </label>
                    <label class="inline-check">
                      <input type="radio" name="matchingScoring" value="PARTIAL" [(ngModel)]="questionForm.scoringType">
                      Partial Match
                    </label>
                  </div>
                </div>
              </section>
            }

            <div class="points-row">
              <div class="field-block compact">
                <label>Points *</label>
                <input type="number" min="1" [(ngModel)]="questionForm.points" name="points" required>
              </div>
              <div class="form-actions">
                <button type="button" class="btn btn-outline" (click)="closeCreateModal()">Cancel</button>
                <button class="btn btn-action" type="submit" [disabled]="savingQuestion">
                  {{ savingQuestion ? "Saving..." : (editingQuestionId ? "Update Question" : "Save Question") }}
                </button>
              </div>
            </div>
          </form>

          <aside class="preview-panel">
            <h3>Preview</h3>
            <p class="preview-question">{{ questionForm.prompt || "Question preview will appear here." }}</p>
            @if (questionForm.mediaUrl.trim()) {
              <p class="preview-note">Media: {{ questionForm.mediaType || "LINK" }} - {{ questionForm.mediaUrl }}</p>
            }
            @if (questionForm.questionType === "SHORT_ANSWER") {
              <p class="preview-note">Expected answer: {{ questionForm.shortAnswer || "-" }}</p>
            } @else if (questionForm.questionType === "MATCHING") {
              <ul class="preview-list">
                @for (prompt of questionForm.matchingPrompts; track $index; let i = $index) {
                  @if (prompt.trim()) {
                    <li>{{ prompt }} => {{ questionForm.matchingCorrect[i] || "..." }}</li>
                  }
                }
              </ul>
            } @else {
              <ul class="preview-list">
                @for (item of previewOptions(); track $index) {
                  <li>{{ item }}</li>
                }
              </ul>
            }
          </aside>
        </div>
      </section>
    </div>
  }

  @if (showPreviewModal) {
    <div class="modal-backdrop" (click)="closeQuizPreview()">
      <section class="modal-shell library-modal" (click)="$event.stopPropagation()">
        <header class="modal-head">
          <h2>Quiz Preview</h2>
          <button type="button" class="close-btn" (click)="closeQuizPreview()">&#10005;</button>
        </header>
        <div class="modal-form">
          @if (previewLoading) {
            <p>Loading preview...</p>
          } @else if (previewData) {
            <p><strong>{{ previewData.quiz.title }}</strong></p>
            <p>{{ previewData.quiz.description }}</p>
            <p class="muted">Time limit: {{ previewData.quiz.timeLimitMinutes }} min | Attempts: {{ previewData.quiz.maxAttempts }}</p>
            <p class="muted">
              Result release:
              {{ previewData.quiz.showResultImmediately ? "Immediate" : (previewData.quiz.resultReleaseAt ? (previewData.quiz.resultReleaseAt | date : "medium") : "Scheduled") }}
            </p>
            <ul class="selected-list">
              @for (question of previewData.questions; track question.questionId) {
                <li>
                  <div>
                    <p class="selected-title">Q{{ question.sortOrder }}. {{ question.prompt }}</p>
                    <p class="selected-meta">{{ question.questionType }} | {{ question.points }} point(s)</p>
                    @if (question.mediaUrl) {
                      <p class="selected-meta">Media: {{ question.mediaType || "LINK" }} - {{ question.mediaUrl }}</p>
                    }
                  </div>
                </li>
              }
            </ul>
          }
        </div>
      </section>
    </div>
  }
</div>
